[FormDataSourceEventHandler(formDataSourceStr(SalesAgreement, SalesAgreementHeader), FormDataSourceEventType::Activated)]
public static void SalesAgreementHeader_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    SalesAgreementHeader          _salesAgreementHeader     = sender.cursor(); //selected record
    FormDataSource      salesAgreementHeader_ds   = sender.formRun().dataSource("SalesAgreementHeader"); //DataSource
    FormRun             element       = sender.formRun(); //form element
    FormControl         myNewButton   = element.design(0).controlName("ETGProformaInvoice");
    //button on the form
    if(_salesAgreementHeader.ETGWorkflowStatus == VersioningDocumentState::Approved)
    {
        myNewButton.enabled(true);
    }
    else
    {
        myNewButton.enabled(false);
    }
}
